+    fn join_cancelled_strengthens_to_worst_reason() {
+        let user: Outcome<i32, &str> = Outcome::Cancelled(CancelReason::user("soft"));
+        let shutdown: Outcome<i32, &str> = Outcome::Cancelled(CancelReason::shutdown());
